var surah034 = {
  number: 34,
  nameArabic: "Saba'",
  nameEnglish: "Saba",
  meaning: "Sheba",
  totalAyahs: 54,
  ayahs: [
    { number: 1, arabic: "ٱلْحَمْدُ لِلَّهِ ٱلَّذِى لَهُۥ مَا فِى ٱلسَّمَٰوَٰتِ وَمَا فِى ٱلْأَرْضِ وَلَهُ ٱلْحَمْدُ فِى ٱلْءَاخِرَةِ ۚ وَهُوَ ٱلْحَكِيمُ ٱلْخَبِيرُ", transliteration: "Alhamdu lillahi allathee lahu ma fee alssamawati wama fee alardi walahu alhamdu fee alakhirati wahuwa alhakeemu alkhabeeru", transliterationB: "Alhamdu lillaahil lazee lahoo maa fis samaawaati wa maa fil ardi wa lahul hamdu fil aakhirah; wa Huwal Hakeemul Khabeer", english: "Praise be to Allah, to Whom belong all things in the heavens and on earth: to Him be Praise in the Hereafter: and He is Full of Wisdom, acquainted with all things", romanUrdu: "Hamd (tareef) us khuda ke liye hai jo aasmaano aur zameen ki har cheez ka maalik hai aur aakhirat mein bhi usi ke liye hamd hai. Woh dana (hikmat wala) aur bakhabar hai" },
    { number: 2, arabic: "يَعْلَمُ مَا يَلِجُ فِى ٱلْأَرْضِ وَمَا يَخْرُجُ مِنْهَا وَمَا يَنزِلُ مِنَ ٱلسَّمَآءِ وَمَا يَعْرُجُ فِيهَا ۚ وَهُوَ ٱلرَّحِيمُ ٱلْغَفُورُ", transliteration: "YaAAlamu ma yaliju fee alardi wama yakhruju minha wama yanzilu mina alssamai wama yaAAruju feeha wahuwa alrraheemu alghafooru", transliterationB: "Ya'lamu maa yaliju fil ardi wa maa yakhruju minhaa wa maa yanzilu minas samaaa'i wa maa ya'ruju feehaa; wa Huwar Raheemul Ghafoor", english: "He knows all that goes into the earth, and all that comes out thereof; all that comes down from the sky and all that ascends thereto and He is the Most Merciful, the Oft-Forgiving", romanUrdu: "Jo kuch zameen mein jata aur jo kuch ussey nikalta hai aur jo kuch aasmaan se utarta hai aur jo kuch usmein chadhta hai, har cheez ko woh jaanta hai.Woh raheem aur gafoor hai" },
    { number: 3, arabic: "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَا تَأْتِينَا ٱلسَّاعَةُ ۖ قُلْ بَلَىٰ وَرَبِّى لَتَأْتِيَنَّكُمْ عَٰلِمِ ٱلْغَيْبِ ۖ لَا يَعْزُبُ عَنْهُ مِثْقَالُ ذَرَّةٍۢ فِى ٱلسَّمَٰوَٰتِ وَلَا فِى ٱلْأَرْضِ وَلَآ أَصْغَرُ مِن ذَٰلِكَ وَلَآ أَكْبَرُ إِلَّا فِى كِتَٰبٍۢ مُّبِينٍۢ", transliteration: "Waqala allatheena kafaroo la tateena alssaAAatu qul bala warabbee latatiyannakum AAalimi alghaybi la yaAAzubu AAanhu mithqalu tharratin fee alssamawati wala fee alardi wala asgharu min thalika wala akbaru illa fee kitabin mubeenin", transliterationB: "Wa qaalal lazeena kafaroo laa taateenas Saa'ah; qul balaa wa Rabbee lataatiyannakum 'Aalimul Ghaib; laa ya'zubu 'anhu misqaalu zarratin fis samaawaati wa laa fil ardi wa laaa asgharu min zaalika wa laaa akbaru illaa fee kitaabim mubeen", english: "The Unbelievers say, \"Never to us will come the Hour\": Say, \"Nay! but most surely, by my Lord, it will come upon you;- by Him Who knows the unseen,- from Whom is not hidden the least little atom in the heavens or on earth: Nor is there anything less than that, or greater, but is in the Record Perspicuous", romanUrdu: "Mukireen kehte hain ke kya baat hai ke qayamat humpar nahin aa rahi hai! Kaho kasam hai mere aalim-ul-gaib parwardigar ki, woh tumpar aa kar raheygi. Ussey zarra barabar (atoms weight/smallest particle) koi cheez na aasmaano mein chupi hui hai na zameen mein na zarre se badi aur na ussey choti, sab kuch ek numaya daftar mein darj hai" },
    { number: 4, arabic: "لِّيَجْزِىَ ٱلَّذِينَ ءَامَنُوا۟ وَعَمِلُوا۟ ٱلصَّٰلِحَٰتِ ۚ أُو۟لَٰٓئِكَ لَهُم مَّغْفِرَةٌۭ وَرِزْقٌۭ كَرِيمٌۭ", transliteration: "Liyajziya allatheena amanoo waAAamiloo alssalihati olaika lahum maghfiratun warizqun kareemun", transliterationB: "Liyajziyal lazeena aamanoo wa 'amilus saalihaat; ulaaa'ika lahum maghfiratunw wa rizqun kareem", english: "That He may reward those who believe and work deeds of righteousness: for such is Forgiveness and a Sustenance Most Generous", romanUrdu: "Aur yeh qayamat isliye aayegi ke jaza de Allah un logon ko jo imaan laye hain aur neik amal karte rahey hain. Unke liye magfirat hai aur rizq-e-kareem" },
    { number: 5, arabic: "وَٱلَّذِينَ سَعَوْ فِىٓ ءَايَٰتِنَا مُعَٰجِزِينَ أُو۟لَٰٓئِكَ لَهُمْ عَذَابٌۭ مِّن رِّجْزٍ أَلِيمٌۭ", transliteration: "Waallatheena saAAaw fee ayatina muAAajizeena olaika lahum AAathabun min rijzin aleemin", transliterationB: "Wallazeena sa'aw feee aayaatinaa mu'aajizeena ulaaa 'ika lahum 'azaabum mir irjzin aleem", english: "But those who strive against Our Signs, to frustrate them,- for such will be a Penalty,- a Punishment most humiliating", romanUrdu: "Aur jin logon ne hamari aayat ko nicha dikhane ke liye zoar lagaya hai, unke liye badhtareen qisam ka dardnaak azaab hai" },
    { number: 6, arabic: "وَيَرَى ٱلَّذِينَ أُوتُوا۟ ٱلْعِلْمَ ٱلَّذِىٓ أُنزِلَ إِلَيْكَ مِن رَّبِّكَ هُوَ ٱلْحَقَّ وَيَهْدِىٓ إِلَىٰ صِرَٰطِ ٱلْعَزِيزِ ٱلْحَمِيدِ", transliteration: "Wayara allatheena ootoo alAAilma allathee onzila ilayka min rabbika huwa alhaqqa wayahdee ila sirati alAAazeezi alhameedi", transliterationB: "Wa yaral lazeena utul 'Ilmal lazeee unzila ilaika mir Rabbika huwal haqqa wa yahdeee ilaaa siraatil 'Azeezil Hameed", english: "And those to whom knowledge has come see that the (Revelation) sent down to thee from thy Lord - that is the Truth, and that it guides to the Path of the Exalted (in might), Worthy of all praise", romanUrdu: "(Aey Nabi), ilm rakhne waley khoob jaante hain ke jo kuch tumhare Rubb ki taraf se tumpar nazil kiya gaya hai woh sarasar haqq hai aur khuda-e-azeez o hameed ka raasta dikhata hai" },
    { number: 7, arabic: "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ هَلْ نَدُلُّكُمْ عَلَىٰ رَجُلٍۢ يُنَبِّئُكُمْ إِذَا مُزِّقْتُمْ كُلَّ مُمَزَّقٍ إِنَّكُمْ لَفِى خَلْقٍۢ جَدِيدٍ", transliteration: "Waqala allatheena kafaroo hal nadullukum AAala rajulin yunabbiokum itha muzziqtum kulla mumazzaqin innakum lafee khalqin jadeedin", transliterationB: "Wa qaalal lazeena kafaroo hal nadullukum 'alaa rajuliny yanabbi 'ukum izaa muzziqtum kulla mumazzaqin innakum lafee khalqin jadeed", english: "The Unbelievers say (in ridicule): \"Shall we point out to you a man that will tell you, when ye are all scattered to pieces in disintegration, that ye shall (then be raised) in a New Creation", romanUrdu: "Munkireen logon se kehte hain “hum batayein tumhein aisa shaks jo khabar deta hai ke jab tumhare jism ka zarra zarra muntashir (bikhara) ho chuka hoga us waqt tum naye sirey se paida kardiye jaogey" },
    { number: 8, arabic: "أَفْتَرَىٰ عَلَى ٱللَّهِ كَذِبًا أَم بِهِۦ جِنَّةٌۢ ۗ بَلِ ٱلَّذِينَ لَا يُؤْمِنُونَ بِٱلْءَاخِرَةِ فِى ٱلْعَذَابِ وَٱلضَّلَٰلِ ٱلْبَعِيدِ", transliteration: "Aftara AAala Allahi kathiban am bihi jinnatun bali allatheena la yuminoona bialakhirati fee alAAathabi waalddalali albaAAeedi", transliterationB: "Aftaraa 'alal laahi kaziban am bihee jinnah; balil lazeena laa yu'minoona bil Aakhirati fil'azaabi waddad laalil ba'eed", english: "Has he invented a falsehood against Allah, or has a spirit (seized) him?\"- Nay, it is those who believe not in the Hereafter, that are in (real) Penalty, and in farthest error", romanUrdu: "Na maloom yeh shaks Allah ke naam se jhoot ghadta hai ya isey junoon (deewana pan) lahiq hai.” Nahin, balke jo log aakhirat ko nahin maante woh azaab mein mubtala honay waley hain aur wahi buri tarah behke huey hain" },
    { number: 9, arabic: "أَفَلَمْ يَرَوْا۟ إِلَىٰ مَا بَيْنَ أَيْدِيهِمْ وَمَا خَلْفَهُم مِّنَ ٱلسَّمَآءِ وَٱلْأَرْضِ ۚ إِن نَّشَأْ نَخْسِفْ بِهِمُ ٱلْأَرْضَ أَوْ نُسْقِطْ عَلَيْهِمْ كِسَفًۭا مِّنَ ٱلسَّمَآءِ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَةًۭ لِّكُلِّ عَبْدٍۢ مُّنِيبٍۢ", transliteration: "Afalam yaraw ila ma bayna aydeehim wama khalfahum mina alssamai waalardi in nasha nakhsif bihimu alarda aw nusqit AAalayhim kisafan mina alssamai inna fee thalika laayatan likulli AAabdin muneebin", transliterationB: "Afalam yaraw ilaa maa baina aydeehim wa maa khalfahum minas samaaa'i wal ard; in nashad nakhsif bihimul arda aw nusqit 'alaihim kisafam minas samaaa'; inna fee zaalika la Aayatal likulli 'abdim muneeb", english: "See they not what is before them and behind them, of the sky and the earth? If We wished, We could cause the earth to swallow them up, or cause a piece of the sky to fall upon them. Verily in this is a Sign for every devotee that turns to Allah (in repentance)", romanUrdu: "Kya inhon ne kabhi us aasmaan o zameen ko nahin dekha jo inhein aagey aur peechey se gheray huey hai? Hum chahein to inhein zameen mein dhansa dein, ya aasmaan ke kuch tukde inpar gira dein. Dar haqeeqat is mein ek naishani hai har us banday ke liye jo khuda ki taraf rujoo karne wala ho" },
    { number: 10, arabic: "۞ وَلَقَدْ ءَاتَيْنَا دَاوُۥدَ مِنَّا فَضْلًۭا ۖ يَٰجِبَالُ أَوِّبِى مَعَهُۥ وَٱلطَّيْرَ ۖ وَأَلَنَّا لَهُ ٱلْحَدِيدَ", transliteration: "Walaqad atayna dawooda minna fadlan ya jibalu awwibee maAAahu waalttayra waalanna lahu alhadeeda", transliterationB: "Wa laqad aatainaa Daawooda minnaa fadlany yaa jibaalu awwibee ma'ahoo wattaira wa alannaa lahul hadeed", english: "We bestowed Grace aforetime on David from ourselves: \"O ye Mountains! Sing ye back the Praises of Allah with him! and ye birds (also)! And We made the iron soft for him", romanUrdu: "Humne Dawood ko apne haan se bada fazal ata kiya tha.(Humne hukum diya ke) aey pahadon (mountains), iske saath hum ahangi karo (unke saath tasbeeh karo) (aur yahi hukum humne) parindon ko diya. Humne lohay (Iron) ko uske liye narm kardiya" },
    { number: 11, arabic: "أَنِ ٱعْمَلْ سَٰبِغَٰتٍۢ وَقَدِّرْ فِى ٱلسَّرْدِ ۖ وَٱعْمَلُوا۟ صَٰلِحًا ۖ إِنِّى بِمَا تَعْمَلُونَ بَصِيرٌۭ", transliteration: "Ani iAAmal sabighatin waqaddir fee alssardi waiAAmaloo salihan innee bima taAAmaloona baseerun", transliterationB: "Ani'mal saabighaatinw wa qaddir fis sardi wa'maloo saalihan innee bimaa ta'maloona Baseer", english: "(Commanding), \"Make thou coast of mail, balancing well the rings of chain armour, and work ye righteousness; for be sure I see (clearly) all that ye do", romanUrdu: "Is hidayat ke saath ke zirein (full coats of mail) bana aur unke halqe theek andaze par rakh. (Aey aale Dawood) neik amal karo. Jo kuch tum karte ho usko main dekh raha hoon" },
    { number: 12, arabic: "وَلِسُلَيْمَٰنَ ٱلرِّيحَ غُدُوُّهَا شَهْرٌۭ وَرَوَاحُهَا شَهْرٌۭ ۖ وَأَسَلْنَا لَهُۥ عَيْنَ ٱلْقِطْرِ ۖ وَمِنَ ٱلْجِنِّ مَن يَعْمَلُ بَيْنَ يَدَيْهِ بِإِذْنِ رَبِّهِۦ ۖ وَمَن يَزِغْ مِنْهُمْ عَنْ أَمْرِنَا نُذِقْهُ مِنْ عَذَابِ ٱلسَّعِيرِ", transliteration: "Walisulaymana alrreeha ghuduwwuha shahrun warawahuha shahrun waasalna lahu AAayna alqitri wamina aljinni man yaAAmalu bayna yadayhi biithni rabbihi waman yazigh minhum AAan amrina nuthiqhu min AAathabi alssaAAeeri", transliterationB: "Wa li-Sulaimaanar reeha ghuduwwuhaa shahrunw wa ra-waahuhaa shahrunw wa asalnaa lahoo 'ainal qitr; wa minal jinni mai ya'malu baina yadaihi bi izni Rabbih; wa mai yazigh minhum 'an amrinaa nuziqhu min 'azaabis sa'eer", english: "And to Solomon (We made) the Wind (obedient): Its early morning (stride) was a month's (journey), and its evening (stride) was a month's (journey); and We made a Font of molten brass to flow for him; and there were Jinns that worked in front of him, by the leave of his Lord, and if any of them turned aside from our command, We made him taste of the Penalty of the Blazing Fire", romanUrdu: "Aur Sulaiman ke liye humne hawa ko musakkhar kardiya, subah ke waqt uska chalna ek mahine ki raah tak aur shaam ke waqt uska chalna ek mahine ki raah tak. Humne uske liye pigley huey tambey(molten brass) ka chashma (spring) baha diya aur aisey Jinn uske taabey kardiye jo apne Rubb ke hukum se uske aagey kaam karte thay. Unmein se jo hamare hukum se sartabi (deviate /swerved) karta usko hum bhadakti hui aag ka maza chakhate" },
    { number: 13, arabic: "يَعْمَلُونَ لَهُۥ مَا يَشَآءُ مِن مَّحَٰرِيبَ وَتَمَٰثِيلَ وَجِفَانٍۢ كَٱلْجَوَابِ وَقُدُورٍۢ رَّاسِيَٰتٍ ۚ ٱعْمَلُوٓا۟ ءَالَ دَاوُۥدَ شُكْرًۭا ۚ وَقَلِيلٌۭ مِّنْ عِبَادِىَ ٱلشَّكُورُ", transliteration: "YaAAmaloona lahu ma yashao min mahareeba watamatheela wajifanin kaaljawabi waqudoorin rasiyatin iAAmaloo ala dawooda shukran waqaleelun min AAibadiya alshshakooru", transliterationB: "Ya'maloona lahoo ma yashaaa'u mim mahaareeba wa tamaaseela wa jifaanin kaljawaabi wa qudoorir raasiyaat; i'maloo aala Daawooda shukraa; wa qaleelum min 'ibaadiyash shakoor", english: "They worked for him as he desired, (making) arches, images, basons as large as reservoirs, and (cooking) cauldrons fixed (in their places): \"Work ye, sons of David, with thanks! but few of My servants are grateful", romanUrdu: "Woh uske liye banate thay jo kuch woh chahta, unchi imaratein, tasvirein, baday baday hauz jaisey lagan (bowls like reservoirs) aur apni jagah se na hatne wali bhari degein. Aey aale Dawood, amal karo shukar ke tareeqe par. Mere bandon mein kam hi shukar guzar hain" },
    { number: 14, arabic: "فَلَمَّا قَضَيْنَا عَلَيْهِ ٱلْمَوْتَ مَا دَلَّهُمْ عَلَىٰ مَوْتِهِۦٓ إِلَّا دَآبَّةُ ٱلْأَرْضِ تَأْكُلُ مِنسَأَتَهُۥ ۖ فَلَمَّا خَرَّ تَبَيَّنَتِ ٱلْجِنُّ أَن لَّوْ كَانُوا۟ يَعْلَمُونَ ٱلْغَيْبَ مَا لَبِثُوا۟ فِى ٱلْعَذَابِ ٱلْمُهِينِ", transliteration: "Falamma qadayna AAalayhi almawta ma dallahum AAala mawtihi illa dabbatu alardi takulu minsaatahu falamma kharra tabayyanati aljinnu an law kanoo yaAAlamoona alghayba ma labithoo fee alAAathabi almuheeni", transliterationB: "Falammaa qadainaa 'alaihil mawta ma dallahum 'alaa mawtiheee illaa daaabbatul ardi taakulu minsa atahoo falammaa kharra tabaiyanatil jinnu al law kaanoo ya'lamoonal ghaiba maa labisoo fil 'azaabil muheen", english: "Then, when We decreed (Solomon's) death, nothing showed them his death except a little worm of the earth, which kept (slowly) gnawing away at his staff: so when he fell down, the Jinns saw plainly that if they had known the unseen, they would not have tarried in the humiliating Penalty (of their Task)", romanUrdu: "Phir jab Sulaiman par humne maut ka faisla nafiz kiya to Jinno ko uski maut ka pata dene wali koi cheez us ghun (worm) ke siwa na thi jo uske asa (staff) ko kha raha tha. Is tarah jab Sualiman gir pada to Jinno par yeh baat khul gayi ke agar woh gaib ke janne waley hotey to is zillat ke azaab mein mubtala na rehte" },
    { number: 15, arabic: "لَقَدْ كَانَ لِسَبَإٍۢ فِى مَسْكَنِهِمْ ءَايَةٌۭ ۖ جَنَّتَانِ عَن يَمِينٍۢ وَشِمَالٍۢ ۖ كُلُوا۟ مِن رِّزْقِ رَبِّكُمْ وَٱشْكُرُوا۟ لَهُۥ ۚ بَلْدَةٌۭ طَيِّبَةٌۭ وَرَبٌّ غَفُورٌۭ", transliteration: "Laqad kana lisabain fee maskanihim ayatun jannatani AAan yameenin washimalin kuloo min rizqi rabbikum waoshkuroo lahu baldatun tayyibatun warabbun ghafoorun", transliterationB: "Laqad kaana li Saba-in fee maskanihim Aayatun jannataani 'ai yameeninw wa shimaalin kuloo mir rizq Rabbikum washkuroolah; baldatun taiyibatunw wa Rabbun Ghafoor", english: "There was, for Saba, aforetime, a Sign in their home-land - two Gardens to the right and to the left. \"Eat of the Sustenance (provided) by your Lord, and be grateful to Him: a territory fair and happy, and a Lord Oft-Forgiving", romanUrdu: "Saba (Sheba) ke liye unke apne maskan (home-land) hi mein ek nishani maujood thi, do baag dayein(right) aur bayein(left). Khao apne Rubb ka diya hua rizq aur shukar baja lao uska, Mulk hai umda o pakeeza aur parwardigar hai bakshish farmane waala" },
    { number: 16, arabic: "فَأَعْرَضُوا۟ فَأَرْسَلْنَا عَلَيْهِمْ سَيْلَ ٱلْعَرِمِ وَبَدَّلْنَٰهُم بِجَنَّتَيْهِمْ جَنَّتَيْنِ ذَوَاتَىْ أُكُلٍ خَمْطٍۢ وَأَثْلٍۢ وَشَىْءٍۢ مِّن سِدْرٍۢ قَلِيلٍۢ", transliteration: "FaaAAradoo faarsalna AAalayhim sayla alAAarimi wabaddalnahum bijannatayhim jannatayni thawatay okulin khamtin waathlin washayin min sidrin qaleelin", transliterationB: "Fa-a''radoo fa-arsalnaa 'alaihim Sailal 'Arimi wa baddalnaahum bijannataihim jannataini azwaatai ukulin khamtinw wa aslinw wa shai'im min sidrin qaleel", english: "But they turned away (from Allah), and We sent against them the Flood (released) from the dams, and We converted their two garden (rows) into \"gardens\" producing bitter fruit, and tamarisks, and some few (stunted) Lote-trees", romanUrdu: "Magar woh mooh moad gaye. Aakhir e kaar humne unpar bandh (dam) todh sailaab (flood) bhej diya aur unke pichle do baaghon (gardens) ke jagah do aur baagh unhein diye jinmein kadwe (bitter) kasaile (tamarisk) phal aur jhaao ke darakht thay aur kuch thodi si beriyan (lote trees)" },
    { number: 17, arabic: "ذَٰلِكَ جَزَيْنَٰهُم بِمَا كَفَرُوا۟ ۖ وَهَلْ نُجَٰزِىٓ إِلَّا ٱلْكَفُورَ", transliteration: "Thalika jazaynahum bima kafaroo wahal nujazee illa alkafoora", transliterationB: "Zaalika jazainaahum bimaa kafaroo wa hal nujaazeee illal kafoor", english: "That was the Requital We gave them because they ungratefully rejected Faith: and never do We give (such) requital except to such as are ungrateful rejecters", romanUrdu: "Yeh tha unke kufr ka badla jo humne unko diya. Aur nashukre Insan ke siwa aisa badla hum aur kisi ko nahin detey" },
    { number: 18, arabic: "وَجَعَلْنَا بَيْنَهُمْ وَبَيْنَ ٱلْقُرَى ٱلَّتِى بَٰرَكْنَا فِيهَا قُرًۭى ظَٰهِرَةًۭ وَقَدَّرْنَا فِيهَا ٱلسَّيْرَ ۖ سِيرُوا۟ فِيهَا لَيَالِىَ وَأَيَّامًا ءَامِنِينَ", transliteration: "WajaAAalna baynahum wabayna alqura allatee barakna feeha quran thahiratan waqaddarna feeha alssayra seeroo feeha layaliya waayyaman amineena", transliterationB: "Wa ja'alnaa bainahum wa bainal qural latee baaraknaa feehaa quran zaahiratanw wa qaddamaa feehas sayr; seeroo feehaa la yaalirya wa aiyaaman aamineen", english: "Between them and the Cities on which We had poured our blessings, We had placed Cities in prominent positions, and between them We had appointed stages of journey in due proportion: \"Travel therein, secure, by night and by day", romanUrdu: "Aur humne unke aur un bastiyon ke darmiyaan, jinko humne barakat ata ki thi, numayan bastiyan basa di thin, aur unmein safar ki musaftein ek andaze par rakh di thin.chalo phiro in raaston mein raat din purey aman ke saath" },
    { number: 19, arabic: "فَقَالُوا۟ رَبَّنَا بَٰعِدْ بَيْنَ أَسْفَارِنَا وَظَلَمُوٓا۟ أَنفُسَهُمْ فَجَعَلْنَٰهُمْ أَحَادِيثَ وَمَزَّقْنَٰهُمْ كُلَّ مُمَزَّقٍ ۚ إِنَّ فِى ذَٰلِكَ لَءَايَٰتٍۢ لِّكُلِّ صَبَّارٍۢ شَكُورٍۢ", transliteration: "Faqaloo rabbana baAAid bayna asfarina wathalamoo anfusahum fajaAAalnahum ahadeetha wamazzaqnahum kulla mumazzaqin inna fee thalika laayatin likulli sabbarin shakoorin", transliterationB: "Faqaaloo Rabbanaa baa'id baina asfaarinaa wa zalamooo anfusahum faja'alnaahum ahaadeesa wa mazzaq naahum kulla mumazzaq; inna fee zaalika la Aayaatil likulli sabbaarin shakoor", english: "But they said: \"Our Lord! Place longer distances between our journey-stages\": but they wronged themselves (therein). At length We made them as a tale (that is told), and We dispersed them all in scattered fragments. Verily in this are Signs for every (soul that is) patiently constant and grateful", romanUrdu: "Magar unhon ne kaha “Aey hamare Rubb, hamare safar ki musafatein lambi karde.” Unhon ne apne upar aap zulm kiya, aakhir e kaar humne unhein afsana bana kar rakh diya aur unhein bilkul tittar bittar kar daala. Yaqeenan ismein nishaniyan hain har us shaks ke liye jo bada saabir(steadfast) o shakir (thankful) ho" },
    { number: 20, arabic: "وَلَقَدْ صَدَّقَ عَلَيْهِمْ إِبْلِيسُ ظَنَّهُۥ فَٱتَّبَعُوهُ إِلَّا فَرِيقًۭا مِّنَ ٱلْمُؤْمِنِينَ", transliteration: "Walaqad saddaqa AAalayhim ibleesu thannahu faittabaAAoohu illa fareeqan mina almumineena", transliterationB: "Wa laqad saddaq 'alaihim Ibleesu zannnabhoo fattaba'oohu illaa fareeqam minal mu'mineen", english: "And on them did Satan prove true his idea, and they followed him, all but a party that believed", romanUrdu: "Unke maamle mein Iblis ne apna gumaan saheeh paya aur unhon ne usi ki pairwi ki, bajuz ek thode se giroh ke jo momin tha" },
    { number: 21, arabic: "وَمَا كَانَ لَهُۥ عَلَيْهِم مِّن سُلْطَٰنٍ إِلَّا لِنَعْلَمَ مَن يُؤْمِنُ بِٱلْءَاخِرَةِ مِمَّنْ هُوَ مِنْهَا فِى شَكٍّۢ ۗ وَرَبُّكَ عَلَىٰ كُلِّ شَىْءٍ حَفِيظٌۭ", transliteration: "Wama kana lahu AAalayhim min sultanin illa linaAAlama man yuminu bialakhirati mimman huwa minha fee shakkin warabbuka AAala kulli shayin hafeethun", transliterationB: "Wa maa kaana lahoo 'alaihim min sultaanin illaa lina'lama mai yu minu bil Aakhirati mimman huwa minhaa fee shakk; wa Rabbuka 'alaa kulli shai'in Hafeez", english: "But he had no authority over them,- except that We might test the man who believes in the Hereafter from him who is in doubt concerning it: and thy Lord doth watch over all things", romanUrdu: "Iblis ko unpar koi iqtedar (authority) haasil na tha magar jo kuch hua woh isliye hua ke hum yeh dekhna chahte thay ke kaun aakhirat ka maanne wala hai aur kaun uski taraf se shakk mein pada hua hai. Tera Rubb har cheez par nigraan (watchful) hai" },
    { number: 22, arabic: "قُلِ ٱدْعُوا۟ ٱلَّذِينَ زَعَمْتُم مِّن دُونِ ٱللَّهِ ۖ لَا يَمْلِكُونَ مِثْقَالَ ذَرَّةٍۢ فِى ٱلسَّمَٰوَٰتِ وَلَا فِى ٱلْأَرْضِ وَمَا لَهُمْ فِيهِمَا مِن شِرْكٍۢ وَمَا لَهُۥ مِنْهُم مِّن ظَهِيرٍۢ", transliteration: "Quli odAAoo allatheena zaAAamtum min dooni Allahi la yamlikoona mithqala tharratin fee alssamawati wala fee alardi wama lahum feehima min shirkin wama lahu minhum min thaheerin", transliterationB: "Qulid 'ul lazeena za'amtum min doonil laahi laa yamlikoona misqaala zarratin fissamaawaati wa laa fil ardi wa maa lahum feehimaa min shirkinw wa maa lahoo minhum min zaheer", english: "Say: \"Call upon other (gods) whom ye fancy, besides Allah: They have no power,- not the weight of an atom,- in the heavens or on earth: No (sort of) share have they therein, nor is any of them a helper to Allah", romanUrdu: "(Aey Nabi, in mushrikeen se) kaho ke pukar dekho apne un maboodon ko jinhein tum Allah ke siwa apna mabood samajhey baithey ho. Woh na aasmaano mein kisi zarra barabar cheez ke maalik hain na zameen mein. Woh aasmaan o zameen ki milkiyat mein shareek bhi nahin hain.Unmein se koi Allah ka madadgaar bhi nahin hai" },
    { number: 23, arabic: "وَلَا تَنفَعُ ٱلشَّفَٰعَةُ عِندَهُۥٓ إِلَّا لِمَنْ أَذِنَ لَهُۥ ۚ حَتَّىٰٓ إِذَا فُزِّعَ عَن قُلُوبِهِمْ قَالُوا۟ مَاذَا قَالَ رَبُّكُمْ ۖ قَالُوا۟ ٱلْحَقَّ ۖ وَهُوَ ٱلْعَلِىُّ ٱلْكَبِيرُ", transliteration: "Wala tanfaAAu alshshafaAAatu AAindahu illa liman athina lahu hatta itha fuzziAAa AAan quloobihim qaloo matha qala rabbukum qaloo alhaqqa wahuwa alAAaliyyu alkabeeru", transliterationB: "Wa laa tanfa'ush shafaa'atu 'indahooo illaa liman azina lah; hattaaa izaa fuzzi'a 'an quloobihim qaaloo maazaa qaala Rabbukum; qaalul haqq, wa Huwal 'Aliyul Kabeer", english: "No intercession can avail in His Presence, except for those for whom He has granted permission. So far (is this the case) that, when terror is removed from their hearts (at the Day of Judgment, then) will they say, 'what is it that your Lord commanded?' they will say, 'That which is true and just; and He is the Most High Most Great", romanUrdu: "Aur Allah ke huzur koi shafaat bhi kisi ke liye nafeh (faida-mand) nahin ho sakti bajuz us shaks ke jiske liye Allah ne sifarish ki ijazat di ho. Hatta ke jab logon ke dilon se ghabrahat door hogi to woh (sifarish karne walon se) puchenge ke tumhare Rubb ne kya jawab diya, woh kahenge ke theek jawab mila hai aur woh buzurg o bartar hai" },
    { number: 24, arabic: "۞ قُلْ مَن يَرْزُقُكُم مِّنَ ٱلسَّمَٰوَٰتِ وَٱلْأَرْضِ ۖ قُلِ ٱللَّهُ ۖ وَإِنَّآ أَوْ إِيَّاكُمْ لَعَلَىٰ هُدًى أَوْ فِى ضَلَٰلٍۢ مُّبِينٍۢ", transliteration: "Qul man yarzuqukum mina alssamawati waalardi quli Allahu wainna aw iyyakum laAAala hudan aw fee dalalin mubeenin", transliterationB: "Qul mai yarzuqukum minas samaawaati wal ardi qulil laahu wa innaaa aw iyyaakum la'alaa hudan aw fee dalaalim mubeen", english: "Say: \"Who gives you sustenance, from the heavens and the earth?\" Say: \"It is Allah; and certain it is that either we or ye are on right guidance or in manifest error", romanUrdu: "(Aey Nabi) insey pucho, “kaun tumko aasmaano aur zameen se rizq deta hai?” kaho “Allah. Ab la muhala (inevitably) hum mein aur tum mein se koi ek hi hidayat par hai ya khuli gumraahi mein pada hua hai.”" },
    { number: 25, arabic: "قُل لَّا تُسْـَٔلُونَ عَمَّآ أَجْرَمْنَا وَلَا نُسْـَٔلُ عَمَّا تَعْمَلُونَ", transliteration: "Qul la tusaloona AAamma ajramna wala nusalu AAamma taAAmaloona", transliterationB: "Qul laa tus'aloona 'ammaaa ajramnaa wa laa nus'alu 'ammaa ta'maloon", english: "Say: \"Ye shall not be questioned as to our sins, nor shall we be questioned as to what ye do", romanUrdu: "Insey kaho, “jo kasoor humne kiya ho uski koi baaz-purs tumse na hogi, aur jo kuch tum kar rahey ho uski koi jawab talabi humse nahin ki jayegi.”" },
    { number: 26, arabic: "قُلْ يَجْمَعُ بَيْنَنَا رَبُّنَا ثُمَّ يَفْتَحُ بَيْنَنَا بِٱلْحَقِّ وَهُوَ ٱلْفَتَّاحُ ٱلْعَلِيمُ", transliteration: "Qul yajmaAAu baynana rabbuna thumma yaftahu baynana bialhaqqi wahuwa alfattahu alAAaleemu", transliterationB: "Qul yajma'u bainanaa Rabbunaa summa yaftahu bainanaa bilhaqq; wa Huwal Fattaahul 'Aleem", english: "Say: \"Our Lord will gather us together and will in the end decide the matter between us (and you) in truth and justice: and He is the one to decide, the One Who knows all", romanUrdu: "Kaho “hamara Rubb humko jamaa karega, phir hamare darmiyan theek theek faisla kardega. Woh aisa zabardast hakim (Great Judge) hai jo sab kuch jaanta hai.”" },
    { number: 27, arabic: "قُلْ أَرُونِىَ ٱلَّذِينَ أَلْحَقْتُم بِهِۦ شُرَكَآءَ ۖ كَلَّا ۚ بَلْ هُوَ ٱللَّهُ ٱلْعَزِيزُ ٱلْحَكِيمُ", transliteration: "Qul arooniya allatheena alhaqtum bihi shurakaa kalla bal huwa Allahu alAAazeezu alhakeemu", transliterationB: "Qul arooniyal lazeena alhaqtum bihee shurakaaa'a kallaa; bal Huwal Laahul 'Azeezul Hakeem", english: "Say: \"Show me those whom ye have joined with Him as partners: by no means (can ye). Nay, He is Allah, the Exalted in Power, the Wise", romanUrdu: "Insey kaho, “zara mujhey dekhao to saheeh woh kaun hastiyan hain jinhein tumne uske saath shareek laga rakkha hai.” Hargiz nahin, zabardast aur dana to bas woh Allah hi hai" },
    { number: 28, arabic: "وَمَآ أَرْسَلْنَٰكَ إِلَّا كَآفَّةًۭ لِّلنَّاسِ بَشِيرًۭا وَنَذِيرًۭا وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", transliteration: "Wama arsalnaka illa kaffatan lilnnasi basheeran wanatheeran walakinna akthara alnnasi la yaAAlamoona", transliterationB: "Wa maaa arsalnaaka illaa kaaffatal linnaasi basheeranw wa nazeeranw wa laakinna aksaran naasi laa ya'lamoon", english: "We have not sent thee but as a universal (Messenger) to men, giving them glad tidings, and warning them (against sin), but most men understand not", romanUrdu: "Aur (Aey Nabi) humne tumko tamaam hi insaano ke liye basheer (khush kabhri dene wala) o nazeer (darr sunane wala) bana kar bheja hai, magar aksar log jaante nahin hain" },
    { number: 29, arabic: "وَيَقُولُونَ مَتَىٰ هَٰذَا ٱلْوَعْدُ إِن كُنتُمْ صَٰدِقِينَ", transliteration: "Wayaqooloona mata hatha alwaAAdu in kuntum sadiqeena", transliterationB: "Wa yaqooloona mataa haazal wa'du in kuntum saadiqeen", english: "They say: \"When will this promise (come to pass) if ye are telling the truth", romanUrdu: "Yeh log tumse kehte hain ke woh (qayamat ka) wada kab poora hoga agar tum sacchey ho" },
    { number: 30, arabic: "قُل لَّكُم مِّيعَادُ يَوْمٍۢ لَّا تَسْتَـْٔخِرُونَ عَنْهُ سَاعَةًۭ وَلَا تَسْتَقْدِمُونَ", transliteration: "Qul lakum meeAAadu yawmin la tastakhiroona AAanhu saAAatan wala tastaqdimoona", transliterationB: "Qul lakum mee'aadu Yawmil laa tastaakhiroona 'anhu saa'atanw wa la tastaqdimoon", english: "Say: \"The appointment to you is for a Day, which ye cannot put back for an hour nor put forward", romanUrdu: "Kaho tumhare liye ek aisey din ki miyad muqarrar hai jiske aane mein na ek ghadi bhar ki taakhir (delay) tum kar sakte ho aur na ek ghadi bhar pehle isey laa sakte ho" },
    { number: 31, arabic: "وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَن نُّؤْمِنَ بِهَٰذَا ٱلْقُرْءَانِ وَلَا بِٱلَّذِى بَيْنَ يَدَيْهِ ۗ وَلَوْ تَرَىٰٓ إِذِ ٱلظَّٰلِمُونَ مَوْقُوفُونَ عِندَ رَبِّهِمْ يَرْجِعُ بَعْضُهُمْ إِلَىٰ بَعْضٍ ٱلْقَوْلَ يَقُولُ ٱلَّذِينَ ٱسْتُضْعِفُوا۟ لِلَّذِينَ ٱسْتَكْبَرُوا۟ لَوْلَآ أَنتُمْ لَكُنَّا مُؤْمِنِينَ", transliteration: "Waqala allatheena kafaroo lan numina bihatha alqurani wala biallathee bayna yadayhi walaw tara ithi alththalimoona mawqoofoona AAinda rabbihim yarjiAAu baAAduhum ila baAAdin alqawla yaqoolu allatheena istudAAifoo lillatheena istakbaroo lawla antum lakunna mumineena", transliterationB: "Wa qaalal lazeena kafaroo lan nu'mina bihaazal Quraani wa laa billazee baina yadayh; wa law taraaa iziz zaalimoona mawqoofoona 'inda Rabbihim yarji'u ba'duhum ilaa ba'dinil qawla yaqoolul lazeenas tud'ifoo lillazeenas takbaroo law laaa antum lakunnaa mu'mineen", english: "The Unbelievers say: \"We shall neither believe in this scripture nor in (any) that (came) before it.\" Couldst thou but see when the wrong-doers will be made to stand before their Lord, throwing back the word (of blame) on one another! Those who had been despised will say to the arrogant ones: \"Had it not been for you, we should certainly have been believers", romanUrdu: "Yeh kaafir kehte hain ke “hum hargiz is Quran ko na maanenge aur na issey pehle aayi hui kisi kitaab ko tasleem karenge”. Kaash tum dekho inka haal us waqt jab yeh zaalim apne Rubb ke huzur khaday hongey us waqt yeh ek dusre par ilzam dharenge. Jo log duniya mein daba kar rakkhe gaye thay woh baday bannay walon se kahenge ke “agar tum na hotay to hum momin hotay.”" },
    { number: 32, arabic: "قَالَ ٱلَّذِينَ ٱسْتَكْبَرُوا۟ لِلَّذِينَ ٱسْتُضْعِفُوٓا۟ أَنَحْنُ صَدَدْنَٰكُمْ عَنِ ٱلْهُدَىٰ بَعْدَ إِذْ جَآءَكُم ۖ بَلْ كُنتُم مُّجْرِمِينَ", transliteration: "Qala allatheena istakbaroo lillatheena istudAAifoo anahnu sadadnakum AAani alhuda baAAda ith jaakum bal kuntum mujrimeena", transliterationB: "Qaalal lazeenas takbaroo lillazeenas tud'ifooo anahnu sadadnaakum 'anil hudaa ba'da iz jaaa'akum bal kuntum mujrimeen", english: "The arrogant ones will say to those who had been despised: \"Was it we who kept you back from Guidance after it reached you? Nay, rather, it was ye who transgressed", romanUrdu: "Woh baday bannay walay in dabay huey logon ko jawab denge “kya humne tumhein us hidayat se roka tha jo tumhare paas aayi thi? Nahin, balke tum khud mujrim thay.”" },
    { number: 33, arabic: "وَقَالَ ٱلَّذِينَ ٱسْتُضْعِفُوا۟ لِلَّذِينَ ٱسْتَكْبَرُوا۟ بَلْ مَكْرُ ٱلَّيْلِ وَٱلنَّهَارِ إِذْ تَأْمُرُونَنَآ أَن نَّكْفُرَ بِٱللَّهِ وَنَجْعَلَ لَهُۥٓ أَندَادًۭا ۚ وَأَسَرُّوا۟ ٱلنَّدَامَةَ لَمَّا رَأَوُا۟ ٱلْعَذَابَ وَجَعَلْنَا ٱلْأَغْلَٰلَ فِىٓ أَعْنَاقِ ٱلَّذِينَ كَفَرُوا۟ ۚ هَلْ يُجْزَوْنَ إِلَّا مَا كَانُوا۟ يَعْمَلُونَ", transliteration: "Waqala allatheena istudAAifoo lillatheena istakbaroo bal makru allayli waalnnahari ith tamuroonana an nakfura biAllahi wanajAAala lahu andadan waasarroo alnnadamata lamma raawoo alAAathaba wajaAAalna alaghlala fee aAAnaqi allatheena kafaroo hal yujzawna illa ma kanoo yaAAmaloona", transliterationB: "Wa qaalal lazeenastud'ifoo lillazeenas takbaroo bal makrul laili wannahaari iz taamuroonanaaa an nakfura billaahi wa naj'ala lahooo andaadaa; wa asarrun nadaamata lammaa ra awul 'azaab; wa ja'alnal aghlaala feee a'naaqil lazeena kafaroo; hal yujzawna illaa maa kanoo ya'maloon", english: "Those who had been despised will say to the arrogant ones: \"Nay! it was a plot (of yours) by day and by night: Behold! Ye (constantly) ordered us to be ungrateful to Allah and to attribute equals to Him!\" They will declare (their) repentance when they see the Penalty: We shall put yokes on the necks of the Unbelievers: It would only be a requital for their (ill) Deeds", romanUrdu: "Woh dabay huey log un baday banne walon se kahenge, ‘Nahin, balke shab-o-roz ki makkari thi jab tum humse kehte thay ke hum Allah se kufr karein aur dusron ko uska humsar thehrayein.” Aakhir e kaar jab yeh log azaab dekhenge to apne dilon mein pachtayenge aur hum in munkireen ke galon mein tauq (bedi/fetters) daal denge. Kya logon ko iske siwa aur koi badla diya ja sakta hai ke jaise aamal unke thay waisi hi jaza woh payein" },
    { number: 34, arabic: "وَمَآ أَرْسَلْنَا فِى قَرْيَةٍۢ مِّن نَّذِيرٍ إِلَّا قَالَ مُتْرَفُوهَآ إِنَّا بِمَآ أُرْسِلْتُم بِهِۦ كَٰفِرُونَ", transliteration: "Wama arsalna fee qaryatin min natheerin illa qala mutrafooha inna bima orsiltum bihi kafiroona", transliterationB: "Wa maaa arsalnaa' fee qaryatim min nazeerin illaa qaala mutrafooaa innaa bimaaa ursiltum bihee kaafiroon", english: "Never did We send a warner to a population, but the wealthy ones among them said: \"We believe not in the (Message) with which ye have been sent", romanUrdu: "Kabhi aisa nahin hua ke humne kisi basti mein ek khabardar karne wala bheja ho aur us basti ke khatey peetay logon ne yeh na kaha ho ke jo paigham tum lekar aaye ho usko hum nahin maante" },
    { number: 35, arabic: "وَقَالُوا۟ نَحْنُ أَكْثَرُ أَمْوَٰلًۭا وَأَوْلَٰدًۭا وَمَا نَحْنُ بِمُعَذَّبِينَ", transliteration: "Waqaloo nahnu aktharu amwalan waawladan wama nahnu bimuAAaththabeena", transliterationB: "Wa qaaloo nahnu aksaru amwaalanw wa awlaadanw wa maa nahnu bimu 'azzabeen", english: "They said: \"We have more in wealth and in sons, and we cannot be punished", romanUrdu: "Unhon ne hamesha yahi kaha ke hum tumse zyada maal aulad rakhte hain aur hum hargiz saza paaney walay nahin hain" },
    { number: 36, arabic: "قُلْ إِنَّ رَبِّى يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ وَيَقْدِرُ وَلَٰكِنَّ أَكْثَرَ ٱلنَّاسِ لَا يَعْلَمُونَ", transliteration: "Qul inna rabbee yabsutu alrrizqa liman yashao wayaqdiru walakinna akthara alnnasi la yaAAlamoona", transliterationB: "Qul inna Rabbee yabsutur rizqa limai yashaaa'u wa yaqdiru wa laakinna aksaran naasi laa ya'lamoon", english: "Say: \"Verily my Lord enlarges and restricts the Provision to whom He pleases, but most men understand not", romanUrdu: "(Aye Nabi), Insey kaho mera Rubb jisey chahta hai kushada (abundant) rizq deta hai aur jisey chahta hai napa tula ata karta hai, magar aksar log iski haqeeqat nahin jaante" },
    { number: 37, arabic: "وَمَآ أَمْوَٰلُكُمْ وَلَآ أَوْلَٰدُكُم بِٱلَّتِى تُقَرِّبُكُمْ عِندَنَا زُلْفَىٰٓ إِلَّا مَنْ ءَامَنَ وَعَمِلَ صَٰلِحًۭا فَأُو۟لَٰٓئِكَ لَهُمْ جَزَآءُ ٱلضِّعْفِ بِمَا عَمِلُوا۟ وَهُمْ فِى ٱلْغُرُفَٰتِ ءَامِنُونَ", transliteration: "Wama amwalukum wala awladukum biallatee tuqarribukum AAindana zulfa illa man amana waAAamila salihan faolaika lahum jazao alddiAAfi bima AAamiloo wahum fee alghurufati aminoona", transliterationB: "Wa maaa amwaalukum wa laaa awlaadukum billatee tuqarribukum 'indanaa zulfaaa illaa man aamana wa 'amila saalihan fa ulaaa'ika lahum jazaaa'ud di'fi bimaa 'amiloo wa hum fil ghurufaati aaminoon", english: "It is not your wealth nor your sons, that will bring you nearer to Us in degree: but only those who believe and work righteousness - these are the ones for whom there is a multiplied Reward for their deeds, while secure they (reside) in the dwellings on high", romanUrdu: "Yeh tumahri daulat aur tumhari aulad nahin hai jo tumhein humse kareeb karti ho. Haan magar jo iman laye aur neik amal karey, yahi log hain jinke liye unke amal ki dohri (double) jaza hai, aur woh baland o baala imaraton mein itminaan se rahenge" },
    { number: 38, arabic: "وَٱلَّذِينَ يَسْعَوْنَ فِىٓ ءَايَٰتِنَا مُعَٰجِزِينَ أُو۟لَٰٓئِكَ فِى ٱلْعَذَابِ مُحْضَرُونَ", transliteration: "Waallatheena yasAAawna fee ayatina muAAajizeena olaika fee alAAathabi muhdaroona", transliterationB: "Wallazeena yas'awna feee Aayaatinaa mu'aajizeena ulaaa'ika fil'azaabi muhdaroon", english: "Those who strive against Our Signs, to frustrate them, will be given over into Punishment", romanUrdu: "Rahey woh log jo hamari aayat ko nicha dikhane ke liye daud-dhoop karte hain, to woh azaab mein mubtala hongey" },
    { number: 39, arabic: "قُلْ إِنَّ رَبِّى يَبْسُطُ ٱلرِّزْقَ لِمَن يَشَآءُ مِنْ عِبَادِهِۦ وَيَقْدِرُ لَهُۥ ۚ وَمَآ أَنفَقْتُم مِّن شَىْءٍۢ فَهُوَ يُخْلِفُهُۥ ۖ وَهُوَ خَيْرُ ٱلرَّٰزِقِينَ", transliteration: "Qul inna rabbee yabsutu alrrizqa liman yashao min AAibadihi wayaqdiru lahu wama anfaqtum min shayin fahuwa yukhlifuhu wahuwa khayru alrraziqeena", transliterationB: "Qul inna Rabbee yabsutur rizqa limai yashaaa'u min 'ibaadihee wa yaqdiru lah; wa maaa anfaqtum min shai'in fahuwa yukhlifuhoo wa Huwa khairur raaziqeen", english: "Say: \"Verily my Lord enlarges and restricts the Sustenance to such of his servants as He pleases: and nothing do ye spend in the least (in His cause) but He replaces it: for He is the Best of those who grant Sustenance", romanUrdu: "(Aey Nabi), Insey kaho, “mera Rubb apne bandon mein se jisey chahta hai khula rizq deta hai aur jisey chahta hai napa tula deta hai. Jo kuch tum kharch kar detey ho uski jagah whai tumko aur deta hai. Woh sab raziqon(providers) se behtar raziq(provider) hai" },
    { number: 40, arabic: "وَيَوْمَ يَحْشُرُهُمْ جَمِيعًۭا ثُمَّ يَقُولُ لِلْمَلَٰٓئِكَةِ أَهَٰٓؤُلَآءِ إِيَّاكُمْ كَانُوا۟ يَعْبُدُونَ", transliteration: "Wayawma yahshuruhum jameeAAan thumma yaqoolu lilmalaikati ahaolai iyyakum kanoo yaAAbudoona", transliterationB: "Wa yawma yahshuruhum jamee'an summa yaqoolu lilmalaaa'ikati a-haaa'ulaaa'i iyyaakum kaanoo ya'budoon", english: "One Day He will gather them all together, and say to the angels, \"Was it you that these men used to worship", romanUrdu: "Aur jis din woh tamaam Insano ko jamaa karega phir Farishton se poochega “kya yeh log tumhari hi ibadat kiya karte thay?”" },
    { number: 41, arabic: "قَالُوا۟ سُبْحَٰنَكَ أَنتَ وَلِيُّنَا مِن دُونِهِم ۖ بَلْ كَانُوا۟ يَعْبُدُونَ ٱلْجِنَّ ۖ أَكْثَرُهُم بِهِم مُّؤْمِنُونَ", transliteration: "Qaloo subhanaka anta waliyyuna min doonihim bal kanoo yaAAbudoona aljinna aktharuhum bihim muminoona", transliterationB: "Qaaloo Subhaanaka Anta waliyyunaa min doonihim bal kaanoo ya'budoonal jinna aksaruhum bihim mu'minoon", english: "They will say, \"Glory to Thee! our (tie) is with Thee - as Protector - not with them. Nay, but they worshipped the Jinns: most of them believed in them", romanUrdu: "To woh jawab denge ke “paak hai aap ki zaat, hamara taaluq to aapse hai na ke in logon se. Dar-asal yeh hamari nahin balke Jinno ki ibadat karte thay, in mein se aksar unhi par iman laye huey thay”" },
    { number: 42, arabic: "فَٱلْيَوْمَ لَا يَمْلِكُ بَعْضُكُمْ لِبَعْضٍۢ نَّفْعًۭا وَلَا ضَرًّۭا وَنَقُولُ لِلَّذِينَ ظَلَمُوا۟ ذُوقُوا۟ عَذَابَ ٱلنَّارِ ٱلَّتِى كُنتُم بِهَا تُكَذِّبُونَ", transliteration: "Faalyawma la yamliku baAAdukum libaAAdin nafAAan wala darran wanaqoolu lillatheena thalamoo thooqoo AAathaba alnnari allatee kuntum biha tukaththiboona", transliterationB: "Fal Yawma laa yamliku ba'dukum liba'din naf'anw wa laa darraa; wa naqoolu lilzeena zalamoo zooqoo 'azaaban Naaril latee kuntum bihaa tukazziboon", english: "So on that Day no power shall they have over each other, for profit or harm: and We shall say to the wrong-doers, \"Taste ye the Penalty of the Fire,- the which ye were wont to deny", romanUrdu: "(Us waqt hum kahenge ke) aaj tum mein se koi na kisi ko faida pahuncha sakta hai na nuksan. Aur zaalimon se hum kehdenge ke ab chakkho us azaab e jahannum ka maza jisey tum jhutlaya karte thay" },
    { number: 43, arabic: "وَإِذَا تُتْلَىٰ عَلَيْهِمْ ءَايَٰتُنَا بَيِّنَٰتٍۢ قَالُوا۟ مَا هَٰذَآ إِلَّا رَجُلٌۭ يُرِيدُ أَن يَصُدَّكُمْ عَمَّا كَانَ يَعْبُدُ ءَابَآؤُكُمْ وَقَالُوا۟ مَا هَٰذَآ إِلَّآ إِفْكٌۭ مُّفْتَرًۭى ۚ وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لِلْحَقِّ لَمَّا جَآءَهُمْ إِنْ هَٰذَآ إِلَّا سِحْرٌۭ مُّبِينٌۭ", transliteration: "Waitha tutla AAalayhim ayatuna bayyinatin qaloo ma hatha illa rajulun yureedu an yasuddakum AAamma kana yaAAbudu abaokum waqaloo ma hatha illa ifkun muftaran waqala allatheena kafaroo lilhaqqi lamma jaahum in hatha illa sihrun mubeenun", transliterationB: "Wa izaa tutlaa 'alaihim Aayaatunaa baiyinaatin qaaloo maa haazaa illaa rajuluny yureedu ai-yasuddakum 'ammaa kaana ya'budu aabaaa'ukum wa qaaloo maa haazaaa illaaa ifkum muftaraa; wa qaalal lazeena kafaroo lilhaqqi lammaa jaaa'ahum in haazaaa illaa sihrum mubeen", english: "When Our Clear Signs are rehearsed to them, they say, \"This is only a man who wishes to hinder you from the (worship) which your fathers practised.\" And they say, \"This is only a falsehood invented!\" and the Unbelievers say of the Truth when it comes to them, \"This is nothing but evident magic", romanUrdu: "In logon ko jab hamari saaf saaf aayat sunayi jaati hain to yeh kahte hain ke “yeh shaks to bas yeh chahta hai ke tumko un maboodon se bargashta (turn away) karde jinki ibadat tumhare baap dada karte aaye hain.” aur kehte hain ke “yeh (Quran) mehaz ek jhoot hai ghada hua.” In kafiron ke saamne jab haqq aaya to unhon ne kehdiya ke “ yeh to sareeh jaadu hai”" },
    { number: 44, arabic: "وَمَآ ءَاتَيْنَٰهُم مِّن كُتُبٍۢ يَدْرُسُونَهَا ۖ وَمَآ أَرْسَلْنَآ إِلَيْهِمْ قَبْلَكَ مِن نَّذِيرٍۢ", transliteration: "Wama ataynahum min kutubin yadrusoonaha wama arsalna ilayhim qablaka min natheerin", transliterationB: "Wa maaa aatainaahum min Kutubiny yadrusoonahaa wa maaa arsalnaaa ilaihim qablaka min nazeer", english: "But We had not given them Books which they could study, nor sent messengers to them before thee as Warners", romanUrdu: "Halaanke na humne in logon ko pehle koi kitaab di thi ke yeh usey padhte hon, aur na tumse pehle inki taraf koi mutanabbeh karne wala bheja tha" },
    { number: 45, arabic: "وَكَذَّبَ ٱلَّذِينَ مِن قَبْلِهِمْ وَمَا بَلَغُوا۟ مِعْشَارَ مَآ ءَاتَيْنَٰهُمْ فَكَذَّبُوا۟ رُسُلِى ۖ فَكَيْفَ كَانَ نَكِيرِ", transliteration: "Wakaththaba allatheena min qablihim wama balaghoo miAAshara ma ataynahum fakaththaboo rusulee fakayfa kana nakeeri", transliterationB: "Wa kazzabal lazeena min qablihim wa maa balaghoo mi'shaara maaa aatainaahum fakazzaboo Rusulee; fakaifa kaana nakeer", english: "And their predecessors rejected (the Truth); these have not received a tenth of what We had granted to those: yet when they rejected My messengers, how (terrible) was My rejection (of them)", romanUrdu: "Insey pehle guzre huey log jhutla chuke hain. Jo kuch humne unhein diya tha uske usrey-asheer (even a tenth/ daswe hissey) ko bhi yeh nahin pahunche hain. Magar jab unhon ne mere Rasoolon ko jhutlaya to dekhlo ke meri saza kaisi sakht thi" },
    { number: 46, arabic: "۞ قُلْ إِنَّمَآ أَعِظُكُم بِوَٰحِدَةٍ ۖ أَن تَقُومُوا۟ لِلَّهِ مَثْنَىٰ وَفُرَٰدَىٰ ثُمَّ تَتَفَكَّرُوا۟ ۚ مَا بِصَاحِبِكُم مِّن جِنَّةٍ ۚ إِنْ هُوَ إِلَّا نَذِيرٌۭ لَّكُم بَيْنَ يَدَىْ عَذَابٍۢ شَدِيدٍۢ", transliteration: "Qul innama aAAithukum biwahidatin an taqoomoo lillahi mathna wafurada thumma tatafakkaroo ma bisahibikum min jinnatin in huwa illa natheerun lakum bayna yaday AAathabin shadeedin", transliterationB: "Qul innamaaa a'izukum biwaahidatin an taqoomoo lillaahi masnaa wa furaadaa summa tatafakkaroo; maa bisaahibikum min jinnah; in huwa illaa nazeerul lakum baina yadai 'azaabin shadeed", english: "Say: \"I do admonish you on one point: that ye do stand up before Allah,- (It may be) in pairs, or (it may be) singly,- and reflect (within yourselves): your Companion is not possessed: he is no less than a warner to you, in face of a terrible Penalty", romanUrdu: "(Aey Nabi), Insey kaho “main tumhein bas ek baat ki naseehat karta hoon, khuda ke liye tum akele akele aur do do mil kar apna dimaag ladaoo aur socho, tumhare saahib[companion(Muhammad)] mein aakhir aisi kaunsi baat hai jo junoon(madness) ki ho? Woh to ek sakht azaab ki aamad (aaney) se pehle tumko mutanabbeh karne wala hai”" },
    { number: 47, arabic: "قُلْ مَا سَأَلْتُكُم مِّنْ أَجْرٍۢ فَهُوَ لَكُمْ ۖ إِنْ أَجْرِىَ إِلَّا عَلَى ٱللَّهِ ۖ وَهُوَ عَلَىٰ كُلِّ شَىْءٍۢ شَهِيدٌۭ", transliteration: "Qul ma saaltukum min ajrin fahuwa lakum in ajriya illa AAala Allahi wahuwa AAala kulli shayin shaheedun", transliterationB: "Qul maa sa-altukum min ajrin fahuwa lakum in ajriya illaa 'alal laahi wa Huwa 'alaa kullin shai-in Shaheed", english: "Say: \"No reward do I ask of you: it is (all) in your interest: my reward is only due from Allah: And He is witness to all things", romanUrdu: "Insey kaho “agar maine tumse koi ajar maanga hai to woh tum hi ko mubarak rahey. Mera ajar to Allah ke zimmey hai aur woh har cheez par gawah hai.”" },
    { number: 48, arabic: "قُلْ إِنَّ رَبِّى يَقْذِفُ بِٱلْحَقِّ عَلَّٰمُ ٱلْغُيُوبِ", transliteration: "Qul inna rabbee yaqthifu bialhaqqi AAallamu alghuyoobi", transliterationB: "Qul inna Rabbee yaqzifu bilhaqq 'Allaamul Ghuyoob", english: "Say: \"Verily my Lord doth cast the (mantle of) Truth (over His servants),- He that has full knowledge of (all) that is hidden", romanUrdu: "Insey kaho “mera Rubb (mujhpar) haqq ka ilqa (inspiration/hurls down) karta hai aur woh tamaam posheeda(chupi hui) haqeeqaton ko jaane wala hai”" },
    { number: 49, arabic: "قُلْ جَآءَ ٱلْحَقُّ وَمَا يُبْدِئُ ٱلْبَٰطِلُ وَمَا يُعِيدُ", transliteration: "Qul jaa alhaqqu wama yubdio albatilu wama yuAAeedu", transliterationB: "Qul jaaa'al haqqu wa maa yubdi'ul baatilu wa maa yu'eed", english: "Say: \"The Truth has arrived, and Falsehood neither creates anything new, nor restores anything", romanUrdu: "Kaho, “haqq aa gaya aur ab baatil ke kiye kuch nahin ho sakta”" },
    { number: 50, arabic: "قُلْ إِن ضَلَلْتُ فَإِنَّمَآ أَضِلُّ عَلَىٰ نَفْسِى ۖ وَإِنِ ٱهْتَدَيْتُ فَبِمَا يُوحِىٓ إِلَىَّ رَبِّىٓ ۚ إِنَّهُۥ سَمِيعٌۭ قَرِيبٌۭ", transliteration: "Qul in dalaltu fainnama adillu AAala nafsee waini ihtadaytu fabima yoohee ilayya rabbee innahu sameeAAun qareebun", transliterationB: "Qul in dalaltu fainnamaaa adillu 'alaa nafsee wa inih-tadaitu fabimaa yoohee ilaiya Rabbee; innahoo Samee'un Qareeb", english: "Say: \"If I am astray, I only stray to the loss of my own soul: but if I receive guidance, it is because of the inspiration of my Lord to me: it is He Who hears all things, and is (ever) near", romanUrdu: "Kaho, “Agar main gumraah ho gaya hoon to meri gumraahi ka wabal mujhpar hai, aur agar main hidayat par hoon to us wahee (revelation) ki bina par hoon jo mera Rubb mere upar nazil karta hai.Woh sabkuch sunta hai aur qareeb hi hai.”" },
    { number: 51, arabic: "وَلَوْ تَرَىٰٓ إِذْ فَزِعُوا۟ فَلَا فَوْتَ وَأُخِذُوا۟ مِن مَّكَانٍۢ قَرِيبٍۢ", transliteration: "Walaw tara ith faziAAoo fala fawta waokhithoo min makanin qareebin", transliterationB: "Wa law taraaa iz fazi'oo falaa fawta wa ukhizoo mim makaanin qareeb", english: "If thou couldst but see when they will quake with terror; but then there will be no escape (for them), and they will be seized from a position (quite) near", romanUrdu: "Kaash tum dekho inhein us waqt jab yeh log ghabraye phir rahey hongey aur kahin bach kar na ja sakengey, balke qareeb hi se pakad liye jayenge" },
    { number: 52, arabic: "وَقَالُوٓا۟ ءَامَنَّا بِهِۦ وَأَنَّىٰ لَهُمُ ٱلتَّنَاوُشُ مِن مَّكَانٍۭ بَعِيدٍۢ", transliteration: "Waqaloo amanna bihi waanna lahumu alttanawushu min makanin baAAeedin", transliterationB: "Wa qaloo aamannaa bihee wa annaa lahumut tanaawushu mim makaanim ba'eed", english: "And they will say, \"We do believe (now) in the (Truth)\"; but how could they receive (Faith) from a position (so far off)", romanUrdu: "Us waqt yeh kahenge ke hum uspar iman le aaye, halanke ab dur nikli hui cheez kahan haath aa sakti hai" },
    { number: 53, arabic: "وَقَدْ كَفَرُوا۟ بِهِۦ مِن قَبْلُ ۖ وَيَقْذِفُونَ بِٱلْغَيْبِ مِن مَّكَانٍۭ بَعِيدٍۢ", transliteration: "Waqad kafaroo bihi min qablu wayaqthifoona bialghaybi min makanin baAAeedin", transliterationB: "Wa qad kafaroo bihee min qablu wa yaqzifoona bilghaibi mim makaanim ba'eed", english: "Seeing that they did reject Faith (entirely) before, and that they (continually) cast (slanders) on the unseen from a position far off", romanUrdu: "Issey pehle yeh kufr kar chuke thay aur bila tehqeeq dur dur ki kodiyan (conjectures) laya karte thay" },
    { number: 54, arabic: "وَحِيلَ بَيْنَهُمْ وَبَيْنَ مَا يَشْتَهُونَ كَمَا فُعِلَ بِأَشْيَاعِهِم مِّن قَبْلُ ۚ إِنَّهُمْ كَانُوا۟ فِى شَكٍّۢ مُّرِيبٍۭ", transliteration: "Waheela baynahum wabayna ma yashtahoona kama fuAAila biashyaAAihim min qablu innahum kanoo fee shakkin mureebin", transliterationB: "Wa heela bainahum wa baina maa yashtahoona kamaa fu'ila bi-ashyaa'ihim min qabl; innahum kaanoo fee shakkim mureeb", english: "And between them and their desires, is placed a barrier, as was done in the past with their partisans: for they were indeed in suspicious (disquieting) doubt", romanUrdu: "Us waqt jis cheez ki yeh tamanna kar rahey hongey ussey mehroom kardiye jayenge jis tarh inke pesh-ro hum mashrab (likes of them before) mehroom ho chuke hongey. Yeh baday gumraah-kun shakk mein paday huey thay" }
  ]
};
